import React, { useState, useRef, useEffect } from 'react';
import {
  Plus,
  Search,
  Edit,
  Trash2,
  RefreshCw,
  Wifi,
  WifiOff,
  Server,
  MoreVertical,
  Save,
  X,
  Terminal,
  HardDrive,
  ExternalLink
} from 'lucide-react';

function Inventory({ devices, loading, onRefresh, onAddDevice, onUpdateDevice, onDeleteDevice, onOpenTerminal, onRunBackup }) {
  const [searchTerm, setSearchTerm] = useState('');
  const [dialogOpen, setDialogOpen] = useState(false);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [selectedDevice, setSelectedDevice] = useState(null);
  const [formData, setFormData] = useState({});
  const [saving, setSaving] = useState(false);
  const [activeTab, setActiveTab] = useState('basic');
  const [dropdownOpen, setDropdownOpen] = useState(null);
  const [dropdownPos, setDropdownPos] = useState({ top: 0, left: 0 });
  const dropdownBtnRef = useRef({});

  // Fechar dropdown ao clicar fora
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (dropdownOpen !== null) {
        const btn = dropdownBtnRef.current[dropdownOpen];
        if (btn && !btn.contains(e.target)) {
          setDropdownOpen(null);
        }
      }
    };
    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, [dropdownOpen]);

  const filteredDevices = devices.filter(device =>
    (device.name || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
    (device.ip || '').includes(searchTerm) ||
    (device.vendor || '').toLowerCase().includes(searchTerm.toLowerCase())
  );

  const deviceTypes = [
    { value: 'bras', label: 'BRAS' },
    { value: 'router', label: 'Router' },
    { value: 'switch', label: 'Switch' },
    { value: 'olt', label: 'OLT' },
  ];

  const vendors = ['Huawei', 'Mikrotik', 'Cisco', 'Juniper', 'Dell', 'HP', 'Outro'];

  const handleOpenAdd = () => {
    setSelectedDevice(null);
    setFormData({
      name: '',
      ip: '',
      port: 22,
      vendor: '',
      device_type: 'router',
      ssh_user: '',
      ssh_password: '',
      snmp_community: '',
      snmp_port: 161,
      web_url: '',
      librenms_id: '',
      backup_enabled: true,
      backup_frequency: 'daily',
      backup_time: '01:00',
    });
    setActiveTab('basic');
    setDialogOpen(true);
  };

  const handleOpenEdit = (device) => {
    setSelectedDevice(device);
    setFormData({
      id: device.id,
      name: device.name,
      ip: device.ip,
      port: device.port || 22,
      vendor: device.vendor || '',
      device_type: device.device_type || 'router',
      ssh_user: device.ssh_user || '',
      ssh_password: device.ssh_password || '',
      snmp_community: device.snmp_community || '',
      snmp_port: device.snmp_port || 161,
      web_url: device.web_url || '',
      librenms_id: device.librenms_id || '',
      backup_enabled: device.backup_enabled !== false,
      backup_frequency: device.backup_frequency || 'daily',
      backup_time: device.backup_time || '01:00',
    });
    setActiveTab('basic');
    setDialogOpen(true);
    setDropdownOpen(null);
  };

  const handleOpenDelete = (device) => {
    setSelectedDevice(device);
    setDeleteDialogOpen(true);
    setDropdownOpen(null);
  };

  const toggleDropdown = (deviceId, e) => {
    e.stopPropagation();
    const rect = e.currentTarget.getBoundingClientRect();

    if (dropdownOpen === deviceId) {
      setDropdownOpen(null);
    } else {
      setDropdownPos({
        top: rect.bottom + window.scrollY,
        left: rect.right - 192, // 192 = largura do dropdown
      });
      setDropdownOpen(deviceId);
    }
  };

  const handleSave = async () => {
    if (!formData.name || !formData.ip) {
      alert('Nome e IP são obrigatórios');
      return;
    }

    setSaving(true);
    try {
      if (selectedDevice) {
        await onUpdateDevice(formData);
      } else {
        await onAddDevice(formData);
      }
      setDialogOpen(false);
    } catch (error) {
      console.error('Save error:', error);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async () => {
    if (!selectedDevice) return;
    setSaving(true);
    try {
      await onDeleteDevice(selectedDevice.id);
      setDeleteDialogOpen(false);
    } catch (error) {
      console.error('Delete error:', error);
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row gap-4 justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Inventário</h1>
          <p className="text-muted-foreground">Gerenciamento de equipamentos de rede</p>
        </div>
        <div className="flex gap-2">
          <button onClick={onRefresh} disabled={loading} className="px-4 py-2 border border-border rounded-lg hover:bg-secondary flex items-center gap-2 disabled:opacity-50">
            <RefreshCw className={'h-4 w-4 ' + (loading ? 'animate-spin' : '')} /> Atualizar
          </button>
          <button onClick={handleOpenAdd} className="px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary/90 flex items-center gap-2">
            <Plus className="h-4 w-4" /> Novo Dispositivo
          </button>
        </div>
      </div>

      {/* Search */}
      <div className="relative">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
        <input
          type="text"
          placeholder="Buscar por nome, IP ou vendor..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-full pl-10 pr-4 py-2 bg-card border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary"
        />
      </div>

      {/* Stats */}
      <div className="grid gap-4 md:grid-cols-4">
        <div className="bg-card p-4 rounded-lg border border-border">
          <div className="text-2xl font-bold">{devices.length}</div>
          <p className="text-xs text-muted-foreground">Total de Dispositivos</p>
        </div>
        <div className="bg-card p-4 rounded-lg border border-border">
          <div className="text-2xl font-bold text-green-500">{devices.filter(d => d.status === 'online').length}</div>
          <p className="text-xs text-muted-foreground">Online</p>
        </div>
        <div className="bg-card p-4 rounded-lg border border-border">
          <div className="text-2xl font-bold text-red-500">{devices.filter(d => d.status === 'offline').length}</div>
          <p className="text-xs text-muted-foreground">Offline</p>
        </div>
        <div className="bg-card p-4 rounded-lg border border-border">
          <div className="text-2xl font-bold text-blue-500">{devices.filter(d => d.device_type === 'bras').length}</div>
          <p className="text-xs text-muted-foreground">BRAS</p>
        </div>
      </div>

      {/* Device List */}
      <div className="bg-card rounded-lg border border-border overflow-hidden">
        <div className="p-4 border-b border-border">
          <h2 className="text-lg font-semibold">Dispositivos</h2>
          <p className="text-sm text-muted-foreground">{filteredDevices.length} de {devices.length} dispositivos</p>
        </div>
        <div className="divide-y divide-border">
          {filteredDevices.map((device) => (
            <div key={device.id} className="flex items-center justify-between p-4 hover:bg-secondary/30">
              <div className="flex items-center gap-4">
                <div className={'p-3 rounded-lg ' + (device.status === 'online' ? 'bg-green-500/10 text-green-500' : 'bg-red-500/10 text-red-500')}>
                  {device.status === 'online' ? <Wifi className="h-6 w-6" /> : <WifiOff className="h-6 w-6" />}
                </div>
                <div>
                  <div className="font-medium flex items-center gap-2">
                    {device.name}
                    {device.web_url && (
                      <a href={device.web_url} target="_blank" rel="noopener noreferrer" className="text-muted-foreground hover:text-primary">
                        <ExternalLink className="h-4 w-4" />
                      </a>
                    )}
                  </div>
                  <div className="text-sm text-muted-foreground">
                    {device.ip}:{device.port} • {device.vendor} {device.model && '• ' + device.model}
                  </div>
                </div>
              </div>
              <div className="flex items-center gap-3">
                <span className="px-2 py-1 bg-primary/20 text-primary rounded text-xs capitalize">{device.device_type}</span>
                {device.pppoe_count > 0 && (
                  <span className="px-2 py-1 bg-blue-500/20 text-blue-400 rounded text-xs">{device.pppoe_count} PPPoE</span>
                )}
                {device.backup_enabled && (
                  <span className="px-2 py-1 bg-green-500/20 text-green-400 rounded text-xs">Backup ON</span>
                )}
                <button 
                  ref={el => dropdownBtnRef.current[device.id] = el}
                  onClick={(e) => toggleDropdown(device.id, e)} 
                  className="p-2 hover:bg-secondary rounded"
                >
                  <MoreVertical className="h-4 w-4" />
                </button>
              </div>
            </div>
          ))}
          {filteredDevices.length === 0 && (
            <div className="p-12 text-center text-muted-foreground">
              <Server className="h-12 w-12 mx-auto mb-4 opacity-50" />
              <p>Nenhum dispositivo encontrado</p>
            </div>
          )}
        </div>
      </div>

      {/* Dropdown Menu - Fixed Position */}
      {dropdownOpen !== null && (
        <div 
          className="fixed z-[9999] w-48 bg-card border border-border rounded-lg shadow-xl"
          style={{ top: dropdownPos.top, left: dropdownPos.left }}
        >
          <button 
            onClick={() => handleOpenEdit(devices.find(d => d.id === dropdownOpen))} 
            className="w-full px-4 py-2.5 text-left hover:bg-secondary flex items-center gap-2 rounded-t-lg"
          >
            <Edit className="h-4 w-4" /> Editar
          </button>
          <button 
            onClick={() => { onOpenTerminal(devices.find(d => d.id === dropdownOpen)); setDropdownOpen(null); }} 
            className="w-full px-4 py-2.5 text-left hover:bg-secondary flex items-center gap-2"
          >
            <Terminal className="h-4 w-4" /> Terminal SSH
          </button>
          <button 
            onClick={() => { onRunBackup(dropdownOpen); setDropdownOpen(null); }} 
            className="w-full px-4 py-2.5 text-left hover:bg-secondary flex items-center gap-2"
          >
            <HardDrive className="h-4 w-4" /> Executar Backup
          </button>
          {devices.find(d => d.id === dropdownOpen)?.librenms_id && (
            <a 
              href={'/librenms/device/device=' + devices.find(d => d.id === dropdownOpen)?.librenms_id + '/'} 
              target="_blank" 
              rel="noopener noreferrer" 
              className="w-full px-4 py-2.5 text-left hover:bg-secondary flex items-center gap-2"
            >
              <ExternalLink className="h-4 w-4" /> Ver no LibreNMS
            </a>
          )}
          <div className="border-t border-border" />
          <button 
            onClick={() => handleOpenDelete(devices.find(d => d.id === dropdownOpen))} 
            className="w-full px-4 py-2.5 text-left hover:bg-secondary text-red-500 flex items-center gap-2 rounded-b-lg"
          >
            <Trash2 className="h-4 w-4" /> Remover
          </button>
        </div>
      )}

      {/* Add/Edit Dialog */}
      {dialogOpen && (
        <div className="fixed inset-0 z-[9998] flex items-center justify-center bg-black/50">
          <div className="bg-card rounded-lg border border-border w-full max-w-2xl max-h-[90vh] overflow-hidden">
            <div className="p-4 border-b border-border flex items-center justify-between">
              <h2 className="text-xl font-semibold">{selectedDevice ? 'Editar Dispositivo' : 'Novo Dispositivo'}</h2>
              <button onClick={() => setDialogOpen(false)} className="p-2 hover:bg-secondary rounded">
                <X className="h-5 w-5" />
              </button>
            </div>

            {/* Tabs */}
            <div className="flex border-b border-border">
              {['basic', 'ssh', 'snmp', 'backup'].map((tab) => (
                <button
                  key={tab}
                  onClick={() => setActiveTab(tab)}
                  className={'px-4 py-2 text-sm font-medium ' + (activeTab === tab ? 'border-b-2 border-primary text-primary' : 'text-muted-foreground hover:text-foreground')}
                >
                  {tab === 'basic' ? 'Básico' : tab === 'ssh' ? 'SSH' : tab === 'snmp' ? 'SNMP' : 'Backup'}
                </button>
              ))}
            </div>

            {/* Form Content */}
            <div className="p-4 space-y-4 overflow-y-auto" style={{ maxHeight: 'calc(90vh - 180px)' }}>
              {activeTab === 'basic' && (
                <>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium mb-1">Nome/Hostname *</label>
                      <input type="text" value={formData.name || ''} onChange={(e) => setFormData({ ...formData, name: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" placeholder="BRAS_NE8000" />
                    </div>
                    <div>
                      <label className="block text-sm font-medium mb-1">Tipo</label>
                      <select value={formData.device_type || 'router'} onChange={(e) => setFormData({ ...formData, device_type: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary">
                        {deviceTypes.map((t) => <option key={t.value} value={t.value}>{t.label}</option>)}
                      </select>
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium mb-1">Endereço IP *</label>
                      <input type="text" value={formData.ip || ''} onChange={(e) => setFormData({ ...formData, ip: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" placeholder="192.168.1.1" />
                    </div>
                    <div>
                      <label className="block text-sm font-medium mb-1">Porta SSH</label>
                      <input type="number" value={formData.port || 22} onChange={(e) => setFormData({ ...formData, port: parseInt(e.target.value) })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">Vendor</label>
                    <select value={formData.vendor || ''} onChange={(e) => setFormData({ ...formData, vendor: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary">
                      <option value="">Selecione</option>
                      {vendors.map((v) => <option key={v} value={v}>{v}</option>)}
                    </select>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium mb-1">Web URL</label>
                      <input type="text" value={formData.web_url || ''} onChange={(e) => setFormData({ ...formData, web_url: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" placeholder="https://192.168.1.1/" />
                    </div>
                    <div>
                      <label className="block text-sm font-medium mb-1">LibreNMS ID</label>
                      <input type="number" value={formData.librenms_id || ''} onChange={(e) => setFormData({ ...formData, librenms_id: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" />
                    </div>
                  </div>
                </>
              )}

              {activeTab === 'ssh' && (
                <>
                  <div>
                    <label className="block text-sm font-medium mb-1">Usuário SSH</label>
                    <input type="text" value={formData.ssh_user || ''} onChange={(e) => setFormData({ ...formData, ssh_user: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" placeholder="admin" />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">Senha SSH</label>
                    <input type="password" value={formData.ssh_password || ''} onChange={(e) => setFormData({ ...formData, ssh_password: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" placeholder="••••••••" />
                  </div>
                </>
              )}

              {activeTab === 'snmp' && (
                <>
                  <div>
                    <label className="block text-sm font-medium mb-1">SNMP Community</label>
                    <input type="text" value={formData.snmp_community || ''} onChange={(e) => setFormData({ ...formData, snmp_community: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" placeholder="public" />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">Porta SNMP</label>
                    <input type="number" value={formData.snmp_port || 161} onChange={(e) => setFormData({ ...formData, snmp_port: parseInt(e.target.value) })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" />
                  </div>
                </>
              )}

              {activeTab === 'backup' && (
                <>
                  <div className="flex items-center justify-between p-4 bg-secondary rounded-lg">
                    <div>
                      <div className="font-medium">Backup Automático</div>
                      <div className="text-sm text-muted-foreground">Ativar backup automático das configurações</div>
                    </div>
                    <button onClick={() => setFormData({ ...formData, backup_enabled: !formData.backup_enabled })} className={'w-12 h-6 rounded-full transition-colors ' + (formData.backup_enabled ? 'bg-primary' : 'bg-secondary border border-border')}>
                      <div className={'w-5 h-5 rounded-full bg-white transition-transform ' + (formData.backup_enabled ? 'translate-x-6' : 'translate-x-0.5')} />
                    </button>
                  </div>
                  {formData.backup_enabled && (
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="block text-sm font-medium mb-1">Frequência</label>
                        <select value={formData.backup_frequency || 'daily'} onChange={(e) => setFormData({ ...formData, backup_frequency: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary">
                          <option value="hourly">A cada hora</option>
                          <option value="daily">Diário</option>
                          <option value="weekly">Semanal</option>
                          <option value="monthly">Mensal</option>
                        </select>
                      </div>
                      <div>
                        <label className="block text-sm font-medium mb-1">Horário</label>
                        <input type="time" value={formData.backup_time || '01:00'} onChange={(e) => setFormData({ ...formData, backup_time: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" />
                      </div>
                    </div>
                  )}
                </>
              )}
            </div>

            {/* Footer */}
            <div className="p-4 border-t border-border flex justify-end gap-2">
              <button onClick={() => setDialogOpen(false)} className="px-4 py-2 border border-border rounded-lg hover:bg-secondary">
                Cancelar
              </button>
              <button onClick={handleSave} disabled={saving} className="px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary/90 flex items-center gap-2 disabled:opacity-50">
                {saving ? <RefreshCw className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                Salvar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Delete Dialog */}
      {deleteDialogOpen && (
        <div className="fixed inset-0 z-[9998] flex items-center justify-center bg-black/50">
          <div className="bg-card rounded-lg border border-border w-full max-w-md p-6">
            <h2 className="text-xl font-semibold mb-2">Confirmar Remoção</h2>
            <p className="text-muted-foreground mb-4">Tem certeza que deseja remover o dispositivo <strong>{selectedDevice?.name}</strong>? Esta ação não pode ser desfeita.</p>
            <div className="flex justify-end gap-2">
              <button onClick={() => setDeleteDialogOpen(false)} className="px-4 py-2 border border-border rounded-lg hover:bg-secondary">
                Cancelar
              </button>
              <button onClick={handleDelete} disabled={saving} className="px-4 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600 flex items-center gap-2 disabled:opacity-50">
                {saving && <RefreshCw className="h-4 w-4 animate-spin" />}
                Remover
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default Inventory;
